from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    target_claims = {
        'CLM-10042', 'CLM-10047', 'CLM-10051',
        'CLM-10058', 'CLM-10061', 'CLM-10071', 'CLM-10082'
    }

    # Search for the file with multiple strategies
    workspace = Path(workspace_path)
    xlsx_files = list(workspace.glob('**/PBC_Claim_Register.xlsx'))
    if not xlsx_files:
        xlsx_files = list(workspace.glob('**/*Claim_Register*.xlsx')) + list(workspace.glob('**/*claim_register*.xlsx'))
    if not xlsx_files:
        all_xlsx = list(workspace.glob('**/*.xlsx'))
        xlsx_files = [f for f in all_xlsx if 'claim' in f.name.lower() or 'register' in f.name.lower()]
    if not xlsx_files:
        all_xlsx = list(workspace.glob('**/*.xlsx'))
        xlsx_files = all_xlsx  # last resort: try any xlsx
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No Claim Register xlsx file found in workspace'}

    found_claims = {}

    # Try all matching xlsx files and all sheets within them
    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
        except Exception as e:
            continue

        for sheet_name in wb.sheetnames:
            ws = wb[sheet_name]

            # Build header map from row 1
            headers = {}
            for col_idx, cell in enumerate(list(ws.iter_rows(min_row=1, max_row=1))[0] if ws.max_row >= 1 else [], 1):
                if cell.value:
                    headers[str(cell.value).strip().lower()] = col_idx

            if not headers:
                continue

            # Identify columns
            claim_id_col = None
            status_col = None
            posting_col = None

            for key, idx in headers.items():
                k = key.lower()
                # Claim ID column
                if claim_id_col is None:
                    if ('claim' in k and ('id' in k or 'num' in k or 'number' in k)) or k in ('claim_id', 'claimid', 'claim id', 'id'):
                        claim_id_col = idx
                # Payment Posting Status column (check this BEFORE claim status to avoid misidentification)
                if 'posting' in k or 'payment posting' in k:
                    posting_col = idx
                # Claim Status column (not payment/posting related)
                if ('status' in k) and ('posting' not in k) and ('payment' not in k):
                    if status_col is None:
                        status_col = idx

            # Fallback: scan header row more carefully
            if claim_id_col is None or status_col is None or posting_col is None:
                for row in ws.iter_rows(min_row=1, max_row=1):
                    for cell in row:
                        val = str(cell.value or '').strip().lower()
                        if claim_id_col is None and 'claim' in val and ('id' in val or 'number' in val or 'num' in val):
                            claim_id_col = cell.column
                        if posting_col is None and 'posting' in val:
                            posting_col = cell.column
                        if status_col is None and 'status' in val and 'posting' not in val and 'payment' not in val:
                            status_col = cell.column

            if claim_id_col is None or status_col is None or posting_col is None:
                continue

            for row in ws.iter_rows(min_row=2):
                claim_val = row[claim_id_col - 1].value
                if claim_val and str(claim_val).strip() in target_claims:
                    claim_id = str(claim_val).strip()
                    status_val = str(row[status_col - 1].value or '').strip()
                    posting_val = str(row[posting_col - 1].value or '').strip()
                    found_claims[claim_id] = {
                        'status': status_val,
                        'posting': posting_val,
                        'file': xlsx_file.name,
                        'sheet': sheet_name
                    }

    if not found_claims:
        return {'pass': False, 'score': 0.0, 'feedback': f'None of the target claims found in any xlsx file/sheet. Target claims: {sorted(target_claims)}'}

    failures = []
    for claim_id in sorted(target_claims):
        if claim_id not in found_claims:
            failures.append(f'{claim_id}: not found in any file/sheet')
            continue
        data = found_claims[claim_id]
        status_lower = data['status'].lower().replace('\u2013', '-').replace('\u2014', '-').replace('\u2012', '-')
        posting_lower = data['posting'].lower()
        status_ok = 'paid' in status_lower and 'full' in status_lower
        posting_ok = 'posted' in posting_lower
        if not status_ok:
            failures.append(f"{claim_id}: Claim Status is '{data['status']}' (expected 'Paid - Full') [file={data['file']}, sheet={data['sheet']}]")
        if not posting_ok:
            failures.append(f"{claim_id}: Payment Posting Status is '{data['posting']}' (expected 'Posted') [file={data['file']}, sheet={data['sheet']}]")

    # Count how many claims fully pass
    passed_count = 0
    for claim_id in target_claims:
        claim_failures = [f for f in failures if claim_id in f]
        if not claim_failures:
            passed_count += 1

    score = passed_count / len(target_claims)

    if failures:
        return {'pass': False, 'score': score, 'feedback': f'Failed checks ({len(failures)} issues): ' + '; '.join(failures)}

    return {'pass': True, 'score': 1.0, 'feedback': f'All 7 target claims have Claim Status=Paid - Full and Payment Posting Status=Posted: {sorted(found_claims.keys())}'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    expected_amounts = {
        'CLM-10042': 247.50,
        'CLM-10047': 180.00,
        'CLM-10051': 315.00,
        'CLM-10058': 92.00,
        'CLM-10061': 410.00,
        'CLM-10071': 900.00,
        'CLM-10082': 650.00,
    }

    # Try to find the file with multiple strategies
    xlsx_files = list(Path(workspace_path).glob('PBC_Claim_Register.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('**/PBC_Claim_Register.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('**/*.xlsx') if 'claim' in f.name.lower()]
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No xlsx file found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])

    # Try all sheets, not just active
    best_result = None
    best_found_count = -1

    for ws in wb.worksheets:
        # Scan first few rows for headers (not always row 1)
        header_row = None
        headers = {}
        for r in range(1, min(ws.max_row + 1, 10)):
            row_vals = {}
            for cell in ws[r]:
                if cell.value:
                    row_vals[str(cell.value).strip().lower()] = cell.column
            # Check if this row looks like a header row
            has_claim = any('claim' in k for k in row_vals)
            has_paid = any('paid' in k or 'payment' in k or 'amount' in k for k in row_vals)
            if has_claim and has_paid:
                headers = row_vals
                header_row = r
                break

        if not headers:
            # Fallback: use row 1
            for cell in ws[1]:
                if cell.value:
                    headers[str(cell.value).strip().lower()] = cell.column
            header_row = 1

        claim_id_col = None
        paid_col = None

        for key, idx in headers.items():
            if claim_id_col is None:
                if ('claim' in key and ('id' in key or 'num' in key or '#' in key)) or key in ('claim_id', 'claim id', 'claimid'):
                    claim_id_col = idx
            if paid_col is None:
                if 'paid amount' in key or 'paid_amount' in key or 'payment amount' in key or 'amount paid' in key or key == 'paid':
                    paid_col = idx

        # Broader fallback for claim column
        if claim_id_col is None:
            for key, idx in headers.items():
                if 'clm' in key or 'claim' in key:
                    claim_id_col = idx
                    break

        # Broader fallback for paid column
        if paid_col is None:
            for key, idx in headers.items():
                if 'paid' in key or 'payment' in key:
                    paid_col = idx
                    break

        if claim_id_col is None or paid_col is None:
            continue

        found = {}
        start_row = (header_row or 1) + 1
        for row in ws.iter_rows(min_row=start_row):
            claim_val = row[claim_id_col - 1].value
            if claim_val and str(claim_val).strip() in expected_amounts:
                claim_id = str(claim_val).strip()
                raw = row[paid_col - 1].value
                if raw is None:
                    found[claim_id] = None
                else:
                    try:
                        found[claim_id] = float(str(raw).replace('$', '').replace(',', '').strip())
                    except (ValueError, TypeError):
                        found[claim_id] = raw

        if len(found) > best_found_count:
            best_found_count = len(found)
            best_result = (found, headers)

    if best_result is None or best_found_count == 0:
        return {'pass': False, 'score': 0.0, 'feedback': 'Could not identify required columns or no matching claims found in any sheet.'}

    found, headers = best_result

    failures = []
    matches = 0
    for claim_id, expected in expected_amounts.items():
        if claim_id not in found:
            failures.append(f'{claim_id}: not found in file')
            continue
        actual = found[claim_id]
        if actual is None:
            failures.append(f'{claim_id}: Paid Amount is blank (expected {expected})')
            continue
        try:
            actual_f = float(actual)
            tolerance = max(expected * 0.01, 0.01)
            if abs(actual_f - expected) > tolerance:
                failures.append(f'{claim_id}: Paid Amount is {actual_f} (expected {expected})')
            else:
                matches += 1
        except (ValueError, TypeError):
            failures.append(f'{claim_id}: Paid Amount is non-numeric: {actual}')

    score = matches / len(expected_amounts)

    if failures:
        return {'pass': False, 'score': score, 'feedback': 'Paid Amount mismatches: ' + '; '.join(failures)}

    return {'pass': True, 'score': 1.0, 'feedback': f'All 7 claims have correct Paid Amounts: {found}'}

