import openpyxl

def verify(workspace_path, external_services_path=None):
    ws_path = Path(workspace_path)
    xlsx_files = list(ws_path.glob('PBC_Claim_Register.xlsx'))
    if not xlsx_files:
        xlsx_files = list(ws_path.glob('**/PBC_Claim_Register.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0,
                'feedback': 'PBC_Claim_Register.xlsx not found in workspace.'}

    wb = openpyxl.load_workbook(xlsx_files[0], data_only=True)
    ws = wb['Claim Register'] if 'Claim Register' in wb.sheetnames else wb.active

    # Build header map from row 1 using exact column names
    headers = {}
    for cell in ws[1]:
        if cell.value is not None:
            headers[str(cell.value).strip()] = cell.column

    required = ['Claim ID', 'Claim Status', 'Payment Posting Status', 'Paid Amount', 'Patient Balance']
    missing = [c for c in required if c not in headers]
    if missing:
        return {'pass': False, 'score': 0.0,
                'feedback': f'Could not find columns: {missing}. Headers found: {list(headers.keys())}'}

    target = 'CLM-10033'
    for row in ws.iter_rows(min_row=2, values_only=True):
        claim_id = str(row[headers['Claim ID'] - 1] or '').strip()
        if claim_id != target:
            continue

        issues = []

        status = str(row[headers['Claim Status'] - 1] or '').strip()
        if status != 'Paid - Full':
            issues.append(f'Claim Status expected "Paid - Full" but found "{status}"')

        posting = str(row[headers['Payment Posting Status'] - 1] or '').strip()
        if posting != 'Reconciled':
            issues.append(f'Payment Posting Status expected "Reconciled" but found "{posting}"')

        try:
            paid = float(row[headers['Paid Amount'] - 1] or 0)
            if abs(paid - 348.00) > 0.01:
                issues.append(f'Paid Amount expected $348.00 but found ${paid:.2f}')
        except (TypeError, ValueError):
            issues.append(f'Paid Amount expected $348.00 but found "{row[headers["Paid Amount"] - 1]}"')

        try:
            bal = float(row[headers['Patient Balance'] - 1] or 0)
            if abs(bal) > 0.01:
                issues.append(f'Patient Balance expected $0.00 but found ${bal:.2f}')
        except (TypeError, ValueError):
            issues.append(f'Patient Balance expected $0.00 but found "{row[headers["Patient Balance"] - 1]}"')

        if issues:
            return {'pass': False, 'score': 0.0,
                    'feedback': f'{target} does not meet requirements: ' + '; '.join(issues)}
        return {'pass': True, 'score': 1.0,
                'feedback': f'{target} verified: Claim Status="Paid - Full", Payment Posting Status="Reconciled", Paid Amount=$348.00, Patient Balance=$0.00'}

    return {'pass': False, 'score': 0.0,
            'feedback': f'{target} not found in PBC_Claim_Register.xlsx'}

from pathlib import Path
import openpyxl
import re


def verify(workspace_path, external_services_path=None):
    # Try to find the file with glob for flexibility
    workspace = Path(workspace_path)
    candidates = list(workspace.glob("**/PBC_Claim_Register.xlsx"))
    if not candidates:
        # Also try case-insensitive
        candidates = [f for f in workspace.glob("**/*.xlsx") if 'claim_register' in f.name.lower() or 'pbc_claim' in f.name.lower()]
    if not candidates:
        return {"pass": False, "score": 0.0, "feedback": f"File PBC_Claim_Register.xlsx not found in {workspace_path}"}

    file_path = candidates[0]

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open workbook: {e}"}

    # Search all sheets for the row
    target_row = None
    header_map = {}
    sheet_name = None

    for ws_name in wb.sheetnames:
        ws = wb[ws_name]
        headers = {}
        # Check first few rows for headers
        header_row_idx = 1
        for r in range(1, min(5, ws.max_row + 1)):
            row_cells = list(ws.iter_rows(min_row=r, max_row=r))[0]
            has_claim = any(cell.value and 'claim' in str(cell.value).strip().lower() for cell in row_cells)
            if has_claim:
                header_row_idx = r
                for col_idx, cell in enumerate(row_cells, start=1):
                    if cell.value is not None:
                        headers[str(cell.value).strip().lower()] = col_idx
                break

        if not headers:
            for col_idx, cell in enumerate(ws[1], start=1):
                if cell.value is not None:
                    headers[str(cell.value).strip().lower()] = col_idx

        # Find claim id column
        claim_id_col = None
        for key in headers:
            if 'claim' in key and 'id' in key:
                claim_id_col = headers[key]
                break
        # Fallback: just 'claim id' or 'claimid'
        if claim_id_col is None:
            for key in headers:
                if key.replace(' ', '').replace('_', '') in ('claimid', 'claimnumber', 'claimno'):
                    claim_id_col = headers[key]
                    break

        if claim_id_col is None:
            continue

        for row in ws.iter_rows(min_row=header_row_idx + 1, max_row=ws.max_row):
            cell_val = row[claim_id_col - 1].value
            if cell_val is not None and str(cell_val).strip().upper() == 'CLM-10089':
                target_row = row
                header_map = headers
                sheet_name = ws_name
                break

        if target_row is not None:
            break

    if target_row is None:
        return {"pass": False, "score": 0.0, "feedback": "Row with Claim ID CLM-10089 not found in any sheet of PBC_Claim_Register.xlsx."}

    def get_cell_value(row, col_idx):
        if col_idx is None:
            return None
        if col_idx - 1 < len(row):
            return row[col_idx - 1].value
        return None

    def find_col(header_map, *keywords):
        """Find column index where all keywords appear in the header key."""
        for key, idx in header_map.items():
            if all(kw in key for kw in keywords):
                return idx
        return None

    issues = []
    details = []
    checks_passed = 0
    total_checks = 4

    # 1. Claim Status must be "In Recovery"
    claim_status_col = find_col(header_map, 'claim', 'status')
    if claim_status_col is None:
        for key, idx in header_map.items():
            if 'status' in key and 'claim' in key:
                claim_status_col = idx
                break
    if claim_status_col is None:
        # Try just 'status' if there's only one status column
        status_cols = [(k, v) for k, v in header_map.items() if 'status' in k and 'payment' not in k and 'posting' not in k]
        if len(status_cols) == 1:
            claim_status_col = status_cols[0][1]
    if claim_status_col is None:
        issues.append("Could not find 'Claim Status' column.")
    else:
        val = get_cell_value(target_row, claim_status_col)
        val_str = str(val).strip() if val is not None else ""
        if val_str.lower().replace('_', ' ').replace('-', ' ') == 'in recovery':
            details.append(f"Claim Status = '{val_str}' (OK)")
            checks_passed += 1
        else:
            issues.append(f"Claim Status expected 'In Recovery', found '{val_str}'.")

    # 2. Payment Posting Status must be blank/None
    pps_col = find_col(header_map, 'payment', 'posting', 'status')
    if pps_col is None:
        for key, idx in header_map.items():
            if 'payment' in key and 'posting' in key:
                pps_col = idx
                break
    if pps_col is None:
        for key, idx in header_map.items():
            if 'posting' in key and 'status' in key:
                pps_col = idx
                break
    if pps_col is None:
        for key, idx in header_map.items():
            if 'payment' in key and 'status' in key:
                pps_col = idx
                break
    if pps_col is None:
        issues.append("Could not find 'Payment Posting Status' column.")
    else:
        val = get_cell_value(target_row, pps_col)
        val_str = str(val).strip() if val is not None else ""
        if val is None or val_str == '' or val_str.lower() in ('none', 'null', 'n/a', 'na', '0', '-', 'blank'):
            details.append(f"Payment Posting Status = blank/None (OK)")
            checks_passed += 1
        else:
            issues.append(f"Payment Posting Status expected blank/None, found '{val_str}'.")

    # 3. Paid Amount must be $0.00
    paid_col = find_col(header_map, 'paid', 'amount')
    if paid_col is None:
        for key, idx in header_map.items():
            if 'paid' in key and ('amt' in key or 'amount' in key):
                paid_col = idx
                break
    if paid_col is None:
        for key, idx in header_map.items():
            if 'paid' in key:
                paid_col = idx
                break
    if paid_col is None:
        # Try 'amount paid'
        for key, idx in header_map.items():
            if 'amount' in key and 'paid' in key:
                paid_col = idx
                break
    if paid_col is None:
        issues.append("Could not find 'Paid Amount' column.")
    else:
        val = get_cell_value(target_row, paid_col)
        try:
            if val is None:
                num_val = 0.0
            else:
                cleaned = re.sub(r'[^\d.\-]', '', str(val))
                num_val = float(cleaned) if cleaned else 0.0
        except (ValueError, TypeError):
            num_val = None

        if num_val is not None and abs(num_val - 0.0) <= 0.05:
            details.append(f"Paid Amount = {val} => {num_val} (OK, expected $0.00)")
            checks_passed += 1
        else:
            issues.append(f"Paid Amount expected $0.00, found '{val}' (parsed as {num_val}).")

    # 4. Patient Balance must be $250.00
    pat_bal_col = find_col(header_map, 'patient', 'balance')
    if pat_bal_col is None:
        for key, idx in header_map.items():
            if 'patient' in key and 'bal' in key:
                pat_bal_col = idx
                break
    if pat_bal_col is None:
        for key, idx in header_map.items():
            if 'pat' in key and 'bal' in key:
                pat_bal_col = idx
                break
    if pat_bal_col is None:
        issues.append("Could not find 'Patient Balance' column.")
    else:
        val = get_cell_value(target_row, pat_bal_col)
        try:
            if val is None:
                num_val = None
            else:
                cleaned = re.sub(r'[^\d.\-]', '', str(val))
                num_val = float(cleaned) if cleaned else None
        except (ValueError, TypeError):
            num_val = None

        if num_val is not None and abs(num_val - 250.0) <= 12.5:  # 5% tolerance
            details.append(f"Patient Balance = {val} => {num_val} (OK, expected ~$250.00)")
            checks_passed += 1
        else:
            issues.append(f"Patient Balance expected $250.00, found '{val}' (parsed as {num_val}).")

    score = checks_passed / total_checks

    if issues:
        feedback = f"FAIL for CLM-10089 in sheet '{sheet_name}': " + "; ".join(issues)
        if details:
            feedback += " | Passed checks: " + "; ".join(details)
        return {"pass": False, "score": score, "feedback": feedback}
    else:
        feedback = f"PASS: CLM-10089 in sheet '{sheet_name}' verified successfully. " + "; ".join(details)
        return {"pass": True, "score": 1.0, "feedback": feedback}
